parameters.jsCode:
// Process AI Analysis Results
const aiResponse = JSON.parse($input.first().json.message.content);

// Calculate risk score and categorize
const riskScore = aiResponse.overall_risk_score || 0;
let riskLevel = 'low';
let route = 'sales_team';
let priority = 'normal';

if (riskScore >= 70) {
  riskLevel = 'high';
  route = 'legal_team';
  priority = 'urgent';
} else if (riskScore >= 40) {
  riskLevel = 'medium';
  route = 'finance_team';
  priority = 'high';
}

// Prepare summary
const summary = {
  contract_id: 'CONTRACT-' + Date.now(),
  file_name: $('Email Trigger').item.binary.attachment.fileName,
  received_at: $now.toISO(),
  parties: aiResponse.parties,
  effective_date: aiResponse.effective_date,
  expiration_date: aiResponse.expiration_date,
  payment_terms: aiResponse.payment_terms,
  financial_obligations: aiResponse.financial_obligations,
  termination_clauses: aiResponse.termination_clauses,
  penalty_clauses: aiResponse.penalty_clauses,
  risk_factors: aiResponse.risk_factors,
  compliance_issues: aiResponse.compliance_issues,
  risk_score: riskScore,
  risk_level: riskLevel,
  recommended_action: aiResponse.recommended_action,
  route_to: route,
  priority: priority,
  drive_url: $('Save to Google Drive').item.json.webViewLink
};

return [{ json: summary }];

